-- EPIC-SERVICE-PAGES-UX C5 wave B — real content fill для pilot pillar
-- /vyvoz-musora/ (Service id=3). Direct SQL — обход Payload Local API (prod без
-- devDeps/tsx). Idempotent: DELETE существующих rows для parent_id=3 перед INSERT.
--
-- Требует ПЕРЕД apply: миграция 20260511_120000_services_blocks_v26_extension
-- (создаёт services_blocks_pricing_table / _process_steps + sub-tables).
--
-- Что делает:
--   1. UPDATE text-content body → чистый markdown-string (фикс markdown-бага:
--      body был Lexical-объектом с raw `## …` внутри одного paragraph node;
--      TextContent renderer для строки корректно рендерит `## ` → h3).
--      Раздел `## Как мы работаем` убран из текста — его покрывает process-steps.
--   2. INSERT calculator-placeholder block (_order=12) — реальный текст
--      «Точный расчёт за 10 минут — пришлите три фото объекта».
--   3. INSERT pricing-table block (_order=13) — 3 тарифа Эконом/Стандарт/Премиум.
--   4. INSERT process-steps block (_order=14) — 6 шагов заявка→…→акт.
--   5. UPDATE services SET use_template_v2=true WHERE id=3 (включить редизайн
--      ТОЛЬКО для vyvoz-musora pillar).
--
-- После apply: `sudo -u deploy pm2 restart obikhod` для ISR cache flush.

BEGIN;

-- ════════════════════════════════════════════════════════════════════════════
-- 0. Cleanup (idempotent re-run)
-- ════════════════════════════════════════════════════════════════════════════
DELETE FROM public.services_blocks_calculator_placeholder WHERE _parent_id = 3;
DELETE FROM public.services_blocks_pricing_table_tiers_features WHERE _parent_id IN (
  SELECT t.id FROM public.services_blocks_pricing_table_tiers t
  JOIN public.services_blocks_pricing_table p ON t._parent_id = p.id WHERE p._parent_id = 3);
DELETE FROM public.services_blocks_pricing_table_tiers WHERE _parent_id IN (
  SELECT id FROM public.services_blocks_pricing_table WHERE _parent_id = 3);
DELETE FROM public.services_blocks_pricing_table WHERE _parent_id = 3;
DELETE FROM public.services_blocks_process_steps_steps WHERE _parent_id IN (
  SELECT id FROM public.services_blocks_process_steps WHERE _parent_id = 3);
DELETE FROM public.services_blocks_process_steps WHERE _parent_id = 3;

-- ════════════════════════════════════════════════════════════════════════════
-- 1. Fix text-content markdown bug — body → clean markdown-string
-- ════════════════════════════════════════════════════════════════════════════
UPDATE public.services_blocks_text_content SET body = '"## Что входит в цену\n\nЦена 12 800 ₽ за объект до 5 м³ — это фиксированная стоимость, в которую входит подача Газели, работа двух грузчиков, погрузка, перевозка на ближайший к району полигон Московской области и акт-приёмки на руки. Полигон уже в смете: вы не доплачиваете за утилизацию отдельно, не получаете «сюрприз» за класс отходов, не подписываете отдельный договор с МСЗ.\n\nЕсли объём больше 5 м³ — подгоняем контейнер 8 или 20 м³. Контейнер на 8 м³ обходится в 14 800 ₽ за объект, на 20 м³ — 18 500 ₽. На стройку или снос частного дома берут контейнер 27 м³, его смета — 23 500 ₽ за один заезд. Контейнер стоит на участке от суток до недели, забираем по готовности; продление каждых следующих суток — 1 200 ₽.\n\nДля собственников частных домов и дач отдельной строкой считается садовый мусор. Ветки, листва, скошенная трава после плановой уборки участка — 14 200 ₽ за объект до 5 м³. Если на участке стоит спиленное дерево с порубочными остатками — берём отдельным тарифом 16 400 ₽ и увозим стволы к щепе на профильное предприятие. Расчистка участка от старых материалов прежних хозяев (плёнка, шифер, бруски, древесные остатки в смеси) — 13 600 ₽ за объект, бригада из двух человек закрывает работу за 2–4 часа.\n\n## Какой мусор берём и какой нет\n\nБерём бытовой мусор, КГМ, строительный мусор IV класса опасности (бой кирпича, стяжка, гипсокартон, древесные остатки, окна, двери), старую мебель, садовый мусор, спецотходы по согласованию (ветки после арбористики, старая кровля, утеплитель, упаковка после ремонта).\n\nНе берём: медицинские отходы (классы Б и В по СанПиН), радиоактивные материалы, баллоны под давлением, ртутные лампы и приборы (для них есть отдельные пункты приёма по 89-ФЗ), просроченные пестициды и агрохимия. На асбестовый шифер и старые автомобильные шины — отдельная смета по согласованию: эти отходы возим на специализированный полигон, цена выше базовой.\n\nЕсли в сумке оказалось «не наше» — звоним собственнику, согласуем замену или отдельный заезд под спецотходы. Без согласия не вывозим: ответственность за неправильную утилизацию по 89-ФЗ — 100–250 тыс. ₽ для юрлица, и эту строчку мы не хотим ни себе, ни вам.\n\n## Сроки и регламент\n\nТиповая заявка: фото утром, смета через 10 минут, выезд послезавтра до 12:00. Бригада из двух человек на Газели 5 м³ закрывает объект за 1–2 часа: погрузка, фиксация, выезд на полигон. Если объект распределён по нескольким адресам в одном районе — собираем маршрут одним выездом и даём дисконт 10% на повторные точки того же дня.\n\nАварийный выезд — за 1–2 часа 24/7. Это режим для УК и ТСЖ, для пожарных ситуаций после ливня, после прорыва канализации, после случайной выгрузки строительной бригадой соседа на ваш участок. Аварийный тариф — 18 400 ₽ за объект до 5 м³, ночной множитель — 1,3. По договору с УК и ТСЖ держим аварийную бригаду в зоне 30 минут от обслуживаемых объектов.\n\nДля собственников частных домов и дач планируем выезд на удобный день, не на «когда машина освободится». Бригадир созванивается за 30 минут до приезда, машина с трекером Глонасс — мы видим в реальном времени, где она и сколько осталось до объекта, и пересылаем эту информацию вам.\n\n## Почему одной бригадой дешевле\n\nИз 17 московских подрядчиков вывоза, которых мы изучили, ни один не закрывает четыре направления одной бригадой: вывоз, арбористика, чистка крыш зимой, демонтаж пристроек. Чаще всего собственник нанимает три разные конторы — на спил дерева, на снос бани, на вывоз остатков, — и платит каждой за подачу транспорта, минимальный заказ и поездку на полигон. Это +35–60% к итоговой смете.\n\nОбиход берёт всё одним договором. Спилили на участке три тополя — увозим стволы и порубочные остатки этой же бригадой, без новой смены машины. Снесли старую баню — вывозим брус, окна, кровельный мусор тем же контейнером 20 м³. Зимой почистили кровлю частного дома от наледи — собрали скол снега в мешки и забрали при следующем выезде. Один договор, одна смета, один акт-приёмки.\n\nДля УК и ТСЖ это означает один счёт в месяц вместо четырёх и одна точка ответственности по штрафам ГЖИ и ОАТИ. Подробности — в разделе [для УК и ТСЖ](/b2b/uk-tszh/).\n\n## Документы, СРО и страховка\n\nКаждый выезд — акт-приёмки. В акте: адрес, объём, тип мусора (бытовой, строительный, КГМ, садовый), полигон назначения, номер машины, бригадир. Для собственников частных домов акт нужен для отчётности перед СНТ или коттеджным посёлком; для УК — для отчётности перед ГЖИ.\n\nОбиход работает по 152-ФЗ (защита персональных данных при приёме фото объектов и контактов), по лицензии Росприроднадзора на транспортирование отходов IV класса опасности и по СРО строителей. Страховой полис гражданской ответственности — 10 млн ₽: если при работе бригада случайно повредит газон, забор или фасад, — компенсируем по своему счёту, без перевыставления собственнику.\n\nПо договору с УК и ТСЖ берём на себя штрафы ГЖИ и ОАТИ в пределах ответственности подрядчика. Если штраф приходит по нашей зоне — оплачиваем по своему счёту, без перевыставления УК. Это в стандартном договоре, не в надбавке. Юристы УК такую формулировку обычно одобряют с первого круга — мы её не прячем, выкладываем в проект договора до подписания.\n\n## Районы и пояс выезда\n\nРаботаем по Москве и ближнему поясу Московской области. По умолчанию — Одинцово, Красногорск, Истра, Мытищи, Балашиха, Подольск, Раменское, Жуковский, Пушкино, Долгопрудный, Химки. Дальше 30 км от МКАД считаем отдельный выезд по 8 000 ₽ за плечо в одну сторону: это покрывает время в пути и амортизацию.\n\nДля СНТ и коттеджных посёлков на удалении 50–80 км от МКАД (направление Минского, Новорижского, Ярославского шоссе) — отдельный недельный график. Один день в неделю бригада идёт по маршруту: 5–7 объектов в одном направлении, цена за объект та же, выезд за плечо — пополам между объектами одного маршрута. Это рабочий способ собственнику дачи в Можайском районе не платить лишнюю тысячу за дорогу.\n\n## Какие фото нужны для сметы\n\nТри фото — это минимум, чтобы посчитать смету по фото без выезда замерщика. Первое фото — общий план объекта с расстояния 3–4 метра, чтобы было видно весь объём (комната, угол участка, кузов вынесенного мусора). Второе фото — крупный план с предметом для масштаба (литровая бутылка, мерная лента, человек рядом). Третье фото — точка погрузки: лестница, лифт, проезд для машины, расстояние от въезда. Если объект распределён по нескольким местам — добавьте фото каждой точки.\n\nНа каждое фото нужны 5–10 секунд: телефон, режим «Авто», без фильтров. Если света мало — включите фонарик второго телефона. Не нужно делать студийные кадры или панорамы: бригадир смотрит на состав мусора, объём и доступ для машины. Эти три параметра определяют, поедет ли Газель 5 м³ или нужен контейнер 8 м³, нужен ли третий грузчик и сколько часов закроет объект.\n\nИногда по фото видно «странные» элементы: бетонная плита под кухней, сваренная металлоконструкция, крупный сейф. По таким объектам бригадир напишет уточняющий вопрос — нужна ли резка, какой размер, есть ли доступ для гидравлики. Это не «лишний» вопрос, это способ не приехать с неправильной техникой и не пересчитать смету на месте.\n\n## Оплата и договор\n\nДля собственников частных домов и квартир — оплата картой через СБП по факту работы, либо наличными бригадиру. Чек присылаем в Telegram или MAX. Если нужен договор как физлицо (для возврата по СНТ или коттеджному посёлку) — подписываем краткую форму на одной странице с реквизитами и описанием объекта.\n\nДля юрлиц, ИП, УК и ТСЖ — счёт-договор с НДС, оплата по безналу с отсрочкой 5–14 банковских дней по согласованию. Закрывающие документы — акт выполненных работ, счёт-фактура, акт-приёмки на объект — присылаем в ЭДО (Диадок, СБИС) или почтой по запросу. Для регулярных объектов УК работаем по рамочному договору с актами по каждому выезду — это упрощает отчётность по концу месяца.\n\nДля разовой большой задачи (снос с вывозом, расчистка участка под продажу) — авансовая часть 30% при подаче техники, остаток по акту. Без аванса работаем по объектам до 25 000 ₽ — это покрывает риск отказа собственника после выезда."'::jsonb WHERE _parent_id = 3;
-- heading: убрана дубль-формулировка «Как мы работаем» (её даёт process-steps),
-- новый heading матчит контент body (цены/регламент/документы).
UPDATE public.services_blocks_text_content SET heading = 'Подробно: цены, регламент, документы' WHERE _parent_id = 3;

